let cart = [];
let qtys = {}; 
meals.forEach(m => qtys[m.id] = 1);

function renderGrid(filteredList = meals) {
    const grid = document.getElementById('grid');
    grid.innerHTML = filteredList.map(m => `
        <div class="meal-card">
            <img src="${m.img}" class="card-img" alt="${m.name}">
            <div class="card-body">
                <div style="color:var(--gray); font-size:0.8rem; margin-bottom: 5px;">🏠 ${m.rest}</div>
                
                <div class="meal-info-wrapper">
                    <div class="meal-name">${m.name}</div>
                    <div style="display:flex; justify-content:space-between; align-items:center;">
                        <span class="price-new">$${m.price.toFixed(2)}</span>
                        <div class="qty-control">
                            <button onclick="changeQty(${m.id},-1)" style="border:none; cursor:pointer; background:none; font-weight:bold;">-</button>
                            <span id="qty-${m.id}">${qtys[m.id]}</span>
                            <button onclick="changeQty(${m.id},1)" style="border:none; cursor:pointer; background:none; font-weight:bold;">+</button>
                        </div>
                    </div>
                </div>

                <button class="reserve-btn" onclick="addToCart(${m.id})">Reserve Meal →</button>
            </div>
        </div>
    `).join('');
}

function filterMeals(btn, category) {
    document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    
    if(category === 'all') {
        renderGrid(meals);
    } else {
        const filtered = meals.filter(m => m.cat === category);
        renderGrid(filtered);
    }
}

function changeQty(id, delta) {
    qtys[id] = Math.max(1, (qtys[id] || 1) + delta);
    document.getElementById(`qty-${id}`).textContent = qtys[id];
}

function toggleCart() {
    document.getElementById('cart-sidebar').classList.toggle('open');
    document.getElementById('dimmer').classList.toggle('active');
}

function addToCart(id) {
    const meal = meals.find(m => m.id === id);
    const exists = cart.find(item => item.id === id);
    
    if(exists) { 
        exists.quantity += qtys[id]; 
    } else { 
        cart.push({...meal, quantity: qtys[id]}); 
    }
    
function showToast() {
    const toast = document.getElementById('toast');
    toast.style.display = 'block';
    setTimeout(() => { toast.style.display = 'none'; }, 2000);
}


    showToast();
    updateCartUI();

}

function updateCartItemQty(id, delta) {
    const item = cart.find(item => item.id === id);
    if (item) {
        item.quantity += delta;
        
        if (item.quantity <= 0) {
            removeFromCart(id);
        } else {
            updateCartUI(); 
        }
    }
}

function updateCartUI() {
    let total = 0;
    const list = document.getElementById('cart-items-list');
    
    if (cart.length === 0) {
        list.innerHTML = `<div style="text-align:center; color:var(--gray); margin-top:50px; font-family:'Syne'">Your basket is empty 🛒</div>`;
        document.getElementById('cart-count').textContent = "0";
        document.getElementById('final-price').textContent = "$0.00";
        return;
    }

    list.innerHTML = cart.map(item => {
        total += item.price * item.quantity;
        return `
            <div class="cart-item" style="display: flex; align-items: center; gap: 12px; margin-bottom: 15px; background: var(--card-bg); padding: 10px; border-radius: 12px;">
                <img src="${item.img}" style="width: 50px; height: 50px; border-radius: 8px; object-fit: cover;">
                <div style="flex-grow:1">
                    <div style="font-weight:700; font-size:0.85rem; margin-bottom: 5px;">${item.name}</div>
                    
                    <div style="display: flex; align-items: center; gap: 10px;">
                        <div class="qty-control" style="padding: 2px 8px; scale: 0.85; transform-origin: left;">
                            <button onclick="updateCartItemQty(${item.id}, -1)" style="border:none; cursor:pointer; background:none; font-weight:bold;">-</button>
                            <span>${item.quantity}</span>
                            <button onclick="updateCartItemQty(${item.id}, 1)" style="border:none; cursor:pointer; background:none; font-weight:bold;">+</button>
                        </div>
                        <span style="font-weight:800; font-size:0.9rem;">$${(item.price * item.quantity).toFixed(2)}</span>
                    </div>
                </div>
                
                <button onclick="removeFromCart(${item.id})" style="background:none; border:none; color:var(--red); cursor:pointer; font-size:1.1rem;">
                    🗑️
                </button>
            </div>`;
    }).join('');

    document.getElementById('cart-count').textContent = cart.length;
    document.getElementById('final-price').textContent = `$${total.toFixed(2)}`;



    const counter = document.getElementById('cart-count');
counter.classList.add('bump');
setTimeout(() => counter.classList.remove('bump'), 400); 
}

function processCheckout() {
    if (cart.length === 0) {
        alert("Your basket is empty!");
        return;
    }
    
    toggleCart(); 
    
    document.getElementById('success-modal').style.display = 'flex';
    
    cart = [];
    updateCartUI();
}

function closeSuccess() {
    document.getElementById('success-modal').style.display = 'none';
}

function removeFromCart(id) {
    cart = cart.filter(item => item.id !== id);
    updateCartUI();
}

function clearFullCart() {
    cart.length = 0; 
    
    updateCartUI();
}

function toggleDarkMode() {
    document.body.classList.toggle('dark-mode');
}

renderGrid();

function openSidebar() {
    document.getElementById("mySidebar").style.width = "350px";
    document.getElementById("overlay").style.display = "block";
}

function closeSidebar() {
    document.getElementById("mySidebar").style.width = "0";
    document.getElementById("overlay").style.display = "none";
}

